zero = ((0).to_bytes(2, 'little', signed=True)).decode("latin1")

def random_array(N, m1):
    # Step 1: Initialize array with 0's
    arr = [0] * N
    
    # Step 2: Randomly select m unique indices
    ones_indices = random.sample(range(N), m1)  # Randomly select m indices
    
    # Step 3: Set the elements at those indices to 1
    for index in ones_indices:
        arr[index] = 1
    arr = np.array(arr, dtype=np.int16)
    return arr

