    def send_DEERNeumann_seq(self, pi_2time, pitime, tau, T, pitimeDEER,
                              buffer, sig_to_ref_wait,sleepTime=0, ifEcho=0):
        psperiod = 2*buffer + 2*(2*pi_2time + 2*tau + pitime) + sig_to_ref_wait
        if ifEcho==1:
            psperiod = 2*buffer + 4*(2*pi_2time + 2*tau + pitime) + 3*sig_to_ref_wait
        freq = 1e9/psperiod
        ch1data = np.array([], dtype=np.int16)
        ch2data = np.array([], dtype=np.int16)

        if self.srate is not None:
            factor = 1e9/self.srate

            # convert all time to "point" in the byte string
            pitime = int(pitime/factor); pi_2time = int(pi_2time/factor); T = int(T/factor)
            pitimeDEER = int(pitimeDEER/factor)
            tau = int(tau/factor); buffer = int(buffer/factor); sig_to_ref_wait = int(sig_to_ref_wait/factor)
        else:
            print('DDS mode')

        T_between_2pihalfpulses = int(tau + pitime + tau)
        first_rest = int(T_between_2pihalfpulses - T)
        second_rest = int(T - pitimeDEER)

        ch1data, ch2data = rest(ch1data, ch2data, buffer)

        ch1data, ch2data = pi_2special(ch1data, ch2data, pi_2time, special_I=0, special_Q=0)
        ch1data, ch2data = rest(ch1data, ch2data, first_rest)
        ch1data, ch2data = piy(ch1data, ch2data, pitimeDEER)
        if second_rest > 0:
            ch1data, ch2data = rest(ch1data, ch2data, second_rest)
        ch1data, ch2data = pi_2special(ch1data, ch2data, pi_2time, special_I=0, special_Q=0)

        if pitimeDEER <= T + pi_2time:
            sig_to_ref_wait_new = sig_to_ref_wait
        else:
            sig_to_ref_wait_new = int(sig_to_ref_wait - (pitimeDEER - T - pi_2time))
        ch1data, ch2data = rest(ch1data, ch2data, sig_to_ref_wait_new)
        ###################################################################################

        ch1data, ch2data = pi_2special(ch1data, ch2data, pi_2time, special_I=0, special_Q=0)
        ch1data, ch2data = rest(ch1data, ch2data, first_rest)
        ch1data, ch2data = piy(ch1data, ch2data, pitimeDEER)
        if second_rest > 0:
            ch1data, ch2data = rest(ch1data, ch2data, second_rest)
        ch1data, ch2data = pi_2special(ch1data, ch2data, pi_2time, special_I=0, special_Q=0)

        if ifEcho==1:
            totalRest = int(sig_to_ref_wait_new + 2*(2*pi_2time + 2*tau + pitime) + sig_to_ref_wait)
            ch1data, ch2data = rest(ch1data, ch2data, totalRest)

        ch1data, ch2data = rest(ch1data, ch2data, buffer)

        ch1plot = ch1data/32767
        ch2plot = ch2data/32767
        ch1bindata, ch2bindata = convert(ch1data, ch2data)

        if self.srate is not None:
            ch1plot = np.repeat(ch1plot,factor)
            ch2plot = np.repeat(ch2plot,factor)
        
        self.upload_waveform(freq, ch1bindata, ch2bindata)  
        time.sleep(sleepTime)
        return(ch1plot, ch2plot)
    
