            ch1data, ch2data = rest(ch1data, ch2data, tau)
            ch1data, ch2data = piy(ch1data, ch2data, pitime)
            ch1data, ch2data = rest(ch1data, ch2data, tau)
            ch1data, ch2data = piy(ch1data, ch2data, pitime)
            ch1data, ch2data = rest(ch1data, ch2data, tau)
            ch1data, ch2data = pix(ch1data, ch2data, pitime)
